onOptionChange:
{{
storeValue("deptReadyfa", false)
.then(() => storeValue("selectedDepartmentFA", Select_FADepartment.selectedOptionValue))
.then(() => GetQuestionsByDeptFA.run())
.then(() => GetAnswersFA.run())
//.then(() => GetDepartmentSignOffFA.run())
.then(() => {
  const existing = {};
  (GetAnswersFA.data || []).forEach(a => {
    existing[String(a.QuestionId)] = {
      YesNo: a.YesNo,
      Answer: a.Answer,
      AnsweredBy: a.AnsweredBy,
      AnsweredDate: a.AnsweredDate,
      ResponsiblePerson: a.ResponsiblePerson,
      Action: a.Action,
      DueDate: a.DueDate
    };
  });
  return storeValue("answers", existing)
    .then(() => storeValue("originalAnswers", JSON.parse(JSON.stringify(existing))));
})
.then(() => storeValue("deptReady", true))
.catch((err) => {
  console.error("Select_FADepartment failed:", err);
  showAlert("Failed to load department data", "error");
  storeValue("deptReady", false);
})
}}
